mapper.select:
SELECT c.course_id, c.course_name, c.instructor, c.start_date, c.end_date, c.description, c.status, c.reg_date, COUNT(s.student_id) AS student_count FROM erp_course c LEFT JOIN erp_training_student s ON c.course_id = s.course_id
AND (c.course_name LIKE '%' || #{keyword} || '%' OR c.instructor LIKE '%' || #{keyword} || '%')
GROUP BY c.course_id, c.course_name, c.instructor, c.start_date, c.end_date, c.description, c.status, c.reg_date ORDER BY c.reg_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT a.ta_id, a.course_id, c.course_name, a.member_id, a.member_name, a.attend_date, a.status FROM erp_training_attendance a LEFT JOIN erp_course c ON a.course_id = c.course_id
AND a.member_name LIKE '%' || #{keyword} || '%'
ORDER BY a.attend_date DESC LIMIT #{limit} OFFSET #{offset}
